 83→                </div>
 84→
 85→                <div className={cn('flex items-center justify-between pt-2')}>
 86→                    {canResetPassword && (
 87→                        <Link
 88→                            href={route('password.request')}
 89→                            className={cn('text-sm text-muted-foreground hover:text-foreground')}
 90→                        >
 91→                            Forgot your password?
 92→                        </Link>
 93→                    )}
 94→
 95→                    <Button
 96→                        type="submit"
 97→                        disabled={processing}
 98→                        className={cn('bg-brand-orange text-white hover:bg-brand-orange/90 ml-auto')}
 99→                    >
100→                        Sign In
101→                    </Button>
102→                </div>
103→
104→                <p className={cn('text-center text-sm text-muted-foreground')}>
105→                    Don't have an account?{' '}
106→                    <Link href={route('register')} className={cn('text-brand-orange hover:underline')}>
107→                        Sign Up
108→                    </Link>
109→                </p>
110→            </form>
111→        </GuestLayout>
112→    );
113→}
